// Formatting utilities for session metrics display

import dayjs from 'dayjs'
import relativeTime from 'dayjs/plugin/relativeTime'

dayjs.extend(relativeTime)

export const formatMs = (ms: number): string => {
  if (ms < 1) return '<1ms'
  if (ms < 1000) return `${Math.round(ms)}ms`
  return `${(ms / 1000).toFixed(2)}s`
}

export const formatDuration = (ms: number | null): string => {
  if (ms == null) return '—'
  const seconds = Math.floor(ms / 1000)
  const minutes = Math.floor(seconds / 60)
  const hours = Math.floor(minutes / 60)
  if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`
  if (minutes > 0) return `${minutes}m ${seconds % 60}s`
  return `${seconds}s`
}

export const formatDate = (iso: string | null): string => {
  if (!iso) return '—'
  return dayjs(iso).format('MMM D, YYYY h:mm A')
}

export const computeAvg = (values: number[]) => {
  if (!values.length) return 0
  return Math.round(values.reduce((a, b) => a + b, 0) / values.length)
}

export const computePercentile = (values: number[], p: number) => {
  if (!values.length) return 0
  const sorted = [...values].sort((a, b) => a - b)
  const idx = Math.min(Math.floor(sorted.length * p), sorted.length - 1)
  return sorted[idx]
}

import type {
  AgentSessionRow,
  EvalCaseRow,
  EvalRunDetail,
  EvalRunRow,
  EvalsFilters,
  PlivoListResponse,
  SessionsFilters,
} from '@/lib/observability-types'

export function createObservabilityApi(baseUrl: string) {
  async function fetchJson<T>(path: string): Promise<T> {
    const res = await fetch(`${baseUrl}${path}`)
    if (!res.ok) throw new Error(`API error: ${res.status} ${res.statusText}`)
    return res.json()
  }

  return {
    listSessions: (limit = 20, offset = 0, filters?: SessionsFilters) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.startedFrom) params.set('started_from', filters.startedFrom)
      if (filters?.startedTo) params.set('started_to', filters.startedTo)
      return fetchJson<PlivoListResponse<AgentSessionRow>>(`/sessions?${params}`)
    },

    getSession: (id: string) =>
      fetchJson<AgentSessionRow>(`/sessions/${id}`),

    listEvalRuns: (limit = 20, offset = 0, filters?: EvalsFilters) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (filters?.agentId) params.set('agent_id', filters.agentId)
      if (filters?.framework && filters.framework.length) {
        params.set('framework', filters.framework.join(','))
      }
      if (filters?.accountId) params.set('account_id', filters.accountId)
      if (filters?.startedFrom) params.set('started_from', filters.startedFrom)
      if (filters?.startedTo) params.set('started_to', filters.startedTo)
      return fetchJson<PlivoListResponse<EvalRunRow>>(`/evals?${params}`)
    },

    getEvalRun: (runId: string) =>
      fetchJson<EvalRunDetail>(`/evals/${runId}`),

    getEvalCase: (runId: string, caseId: string) =>
      fetchJson<EvalCaseRow & { api_id?: string }>(`/evals/${runId}/cases/${caseId}`),
  }
}

export type ObservabilityApi = ReturnType<typeof createObservabilityApi>

import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from 'react'
import { createObservabilityApi, type ObservabilityApi } from '@/lib/observability-api'
import type { AgentSessionRow } from '@/lib/observability-types'

interface ObservabilityContextValue {
  api: ObservabilityApi
  session: AgentSessionRow | null
  sessionLoading: boolean
  sessionError: string | null
  highlightedTurn: number | null
  setHighlightedTurn: (turn: number | null) => void
}

const ObservabilityContext = createContext<ObservabilityContextValue | null>(null)

export function AgentObservabilityProvider({
  baseUrl,
  sessionId,
  children,
}: {
  baseUrl: string
  sessionId?: string
  children: ReactNode
}) {
  const api = useMemo(() => createObservabilityApi(baseUrl), [baseUrl])
  const [session, setSession] = useState<AgentSessionRow | null>(null)
  const [sessionLoading, setSessionLoading] = useState(!!sessionId)
  const [sessionError, setSessionError] = useState<string | null>(null)
  const [highlightedTurn, setHighlightedTurn] = useState<number | null>(null)

  useEffect(() => {
    if (!sessionId) {
      setSession(null)
      setSessionLoading(false)
      return
    }
    setSessionLoading(true)
    setSessionError(null)
    api
      .getSession(sessionId)
      .then(setSession)
      .catch((e) => setSessionError(e.message))
      .finally(() => setSessionLoading(false))
  }, [api, sessionId])

  const value = useMemo<ObservabilityContextValue>(
    () => ({
      api,
      session,
      sessionLoading,
      sessionError,
      highlightedTurn,
      setHighlightedTurn,
    }),
    [api, session, sessionLoading, sessionError, highlightedTurn],
  )

  return (
    <ObservabilityContext.Provider value={value}>
      {children}
    </ObservabilityContext.Provider>
  )
}

export function useObservabilityContext() {
  const ctx = useContext(ObservabilityContext)
  if (!ctx) {
    throw new Error('useObservabilityContext must be used within AgentObservabilityProvider')
  }
  return ctx
}

import { useEffect, useMemo, useState } from 'react'
import { useObservabilityContext } from '@/lib/observability-provider'
import type {
  AgentSessionRow,
  ChatItem,
  EvalCaseRow,
  EvalRunDetail,
  EvalRunRow,
  EvalsFilters,
  MetricsSummary,
  PlivoMeta,
  SessionEvent,
  SessionMetrics,
  SessionsFilters,
  TurnRecord,
} from '@/lib/observability-types'

// ---------------------------------------------------------------------------
// useSessions — fetches paginated session list
// ---------------------------------------------------------------------------

export function useSessions(
  limit = 20,
  initialOffset = 0,
  filters?: SessionsFilters,
) {
  const { api } = useObservabilityContext()
  const [sessions, setSessions] = useState<AgentSessionRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset: initialOffset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [offset, setOffset] = useState(initialOffset)

  const accountId = filters?.accountId
  const startedFrom = filters?.startedFrom
  const startedTo = filters?.startedTo

  // Sync offset when the caller passes a live initialOffset (e.g. from URL
  // state). Callers who drive pagination via setOffset pass a stable 0 and
  // this no-ops after mount.
  useEffect(() => {
    setOffset(initialOffset)
  }, [initialOffset])

  useEffect(() => {
    setOffset(0)
  }, [accountId, startedFrom, startedTo])

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listSessions(limit, offset, { accountId, startedFrom, startedTo })
      .then((res) => {
        if (cancelled) return
        setSessions(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => {
        if (!cancelled) setError(e.message)
      })
      .finally(() => {
        if (!cancelled) setLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [api, limit, offset, accountId, startedFrom, startedTo])

  return { sessions, meta, loading, error, offset, setOffset }
}

// ---------------------------------------------------------------------------
// useSession — returns the current session from provider context
// ---------------------------------------------------------------------------

export function useSession() {
  const { session, sessionLoading, sessionError } = useObservabilityContext()
  return {
    session,
    loading: sessionLoading,
    error: sessionError,
  }
}

// ---------------------------------------------------------------------------
// useTimeline — derives timeline data from current session
// ---------------------------------------------------------------------------

export function useTimeline() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const recordUrl: string | null = session?.record_url ?? null
  const sessionCreatedAt: string | undefined = session?.created_at

  return { metrics, recordUrl, sessionCreatedAt, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// useTranscript — derives transcript data from current session
// ---------------------------------------------------------------------------

export function useTranscript() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const turns: TurnRecord[] = useMemo(
    () => metrics?.turns ?? [],
    [metrics],
  )
  const chatHistory: ChatItem[] | null = session?.chat_history ?? null

  return { turns, chatHistory, metrics, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// usePerformance — derives performance metrics from current session
// ---------------------------------------------------------------------------

export function usePerformance() {
  const { session } = useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const summary: MetricsSummary | null = metrics?.summary ?? null

  return { metrics, summary }
}

// ---------------------------------------------------------------------------
// useEvents / useOptions — raw session report slices
// ---------------------------------------------------------------------------

export function useEvents(): SessionEvent[] | null {
  const { session } = useObservabilityContext()
  return session?.events ?? null
}

export function useOptions(): Record<string, unknown> | null {
  const { session } = useObservabilityContext()
  return session?.options ?? null
}

// ---------------------------------------------------------------------------
// useEvalRuns / useEvalRun / useEvalCase — eval dashboard data
// ---------------------------------------------------------------------------

export function useEvalRuns(
  limit = 20,
  initialOffset = 0,
  filters?: EvalsFilters,
) {
  const { api } = useObservabilityContext()
  const [runs, setRuns] = useState<EvalRunRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset: initialOffset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [offset, setOffset] = useState(initialOffset)

  const { agentId, framework, accountId, startedFrom, startedTo } = filters ?? {}
  const frameworkKey = (framework ?? []).slice().sort().join(',')

  useEffect(() => {
    setOffset(initialOffset)
  }, [initialOffset])

  useEffect(() => {
    setOffset(0)
  }, [agentId, frameworkKey, accountId, startedFrom, startedTo])

  useEffect(() => {
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .listEvalRuns(limit, offset, {
        agentId,
        framework: framework && framework.length ? framework : undefined,
        accountId,
        startedFrom,
        startedTo,
      })
      .then((res) => {
        if (cancelled) return
        setRuns(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api, limit, offset, agentId, frameworkKey, accountId, startedFrom, startedTo])

  return { runs, meta, loading, error, offset, setOffset }
}

export function useEvalRun(runId: string | undefined) {
  const { api } = useObservabilityContext()
  const [run, setRun] = useState<EvalRunDetail | null>(null)
  const [loading, setLoading] = useState(!!runId)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!runId) {
      setRun(null)
      setLoading(false)
      return
    }
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getEvalRun(runId)
      .then((r) => !cancelled && setRun(r))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, runId])

  return { run, loading, error }
}

export function useEvalCase(runId: string | undefined, caseId: string | undefined) {
  const { api } = useObservabilityContext()
  const [evalCase, setEvalCase] = useState<EvalCaseRow | null>(null)
  const [loading, setLoading] = useState(!!(runId && caseId))
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (!runId || !caseId) {
      setEvalCase(null)
      setLoading(false)
      return
    }
    let cancelled = false
    setLoading(true)
    setError(null)
    api
      .getEvalCase(runId, caseId)
      .then((c) => !cancelled && setEvalCase(c))
      .catch((e) => !cancelled && setError(e.message))
      .finally(() => !cancelled && setLoading(false))
    return () => { cancelled = true }
  }, [api, runId, caseId])

  return { evalCase, loading, error }
}

import { useMemo, useState } from 'react'
import type { ColumnDef } from '@tanstack/react-table'
import { parseAsString, useQueryState } from 'nuqs'
import { ArrowLeft, ExternalLink, FlaskConical, GitBranch, GitCommit } from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet'
import { Skeleton } from '@/components/ui/skeleton'
import { DataTableColumnHeader } from '@/components/data-table/data-table-column-header'
import { DataTableToolbar } from '@/components/data-table/data-table-toolbar'
import { ObsDataTable } from '@/components/data-table/obs-data-table'
import { useDataTable } from '@/hooks/use-data-table'
import { cn } from '@/lib/utils'
import { formatDate, formatDuration } from '@/lib/observability-format'
import { useEvalRun } from '@/lib/observability-hooks'
import type { CaseStatus, EvalCaseRow } from '@/lib/observability-types'
import { EvalCaseDetailPage } from '@/components/eval-case-detail-page'

const STATUS_OPTIONS: Array<{ label: string; value: CaseStatus }> = [
  { label: 'Passed', value: 'passed' },
  { label: 'Failed', value: 'failed' },
  { label: 'Errored', value: 'errored' },
  { label: 'Skipped', value: 'skipped' },
]

/** Duration thresholds for eval cases: good ≤ 2s, okay 2–5s, bad > 5s.
 * Wider than voice latencies since eval cases often involve multi-turn
 * conversations or slow fixtures. */
function durationToneClass(ms: number | null): string {
  if (ms == null) return ''
  if (ms <= 2000) return 'text-[hsl(var(--success-fg,var(--success)))]'
  if (ms <= 5000) return 'text-[hsl(var(--warning-fg,var(--warning)))]'
  return 'text-[hsl(var(--destructive))]'
}

const STATUS_TONE: Record<CaseStatus, string> = {
  passed:
    'bg-[hsl(var(--success-bg))] text-[hsl(var(--success-fg,var(--success)))] border-[hsl(var(--success-border))]',
  failed:
    'bg-[hsl(var(--destructive-bg))] text-[hsl(var(--destructive))] border-[hsl(var(--destructive-border))]',
  errored:
    'bg-[hsl(var(--warning-bg))] text-[hsl(var(--warning-fg,var(--warning)))] border-[hsl(var(--warning-border))]',
  skipped: 'bg-muted text-muted-foreground border-border',
}

function StatusChip({ status }: { status: CaseStatus }) {
  return (
    <span
      className={cn(
        'inline-flex items-center h-[22px] px-2 rounded-full border text-xxs-600 capitalize',
        STATUS_TONE[status],
      )}
    >
      {status}
    </span>
  )
}

type StatTone = 'good' | 'warn' | 'bad' | 'zero' | 'default'

/** Card tones mirror the session-detail metric tiles: good/warn/bad pick
 * up the semantic token family (success / warning / destructive). `zero`
 * mutes the value so 0 counts don't compete with real signals. */
function StatCard({
  label,
  value,
  suffix,
  tone = 'default',
  meterPct,
}: {
  label: string
  value: string | number
  suffix?: string
  tone?: StatTone
  meterPct?: number
}) {
  const valueClass =
    tone === 'good'
      ? 'text-[hsl(var(--success-fg,var(--success)))]'
      : tone === 'warn'
        ? 'text-[hsl(var(--warning-fg,var(--warning)))]'
        : tone === 'bad'
          ? 'text-[hsl(var(--destructive))]'
          : tone === 'zero'
            ? 'text-muted-foreground'
            : ''
  const borderClass =
    tone === 'good'
      ? 'border-[hsl(var(--success-border))]'
      : tone === 'warn'
        ? 'border-[hsl(var(--warning-border))]'
        : tone === 'bad'
          ? 'border-[hsl(var(--destructive-border))]'
          : ''
  const meterClass =
    tone === 'good'
      ? 'bg-[hsl(var(--success-fg,var(--success)))]'
      : tone === 'warn'
        ? 'bg-[hsl(var(--warning-fg,var(--warning)))]'
        : tone === 'bad'
          ? 'bg-[hsl(var(--destructive))]'
          : 'bg-foreground'
  return (
    <Card className={cn('relative overflow-hidden', borderClass)}>
      <CardHeader className="pb-2">
        <CardTitle className="text-xs-600 uppercase tracking-wide text-muted-foreground">
          {label}
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className={cn('text-h1-600 font-semibold tabular-nums flex items-baseline gap-2', valueClass)}>
          {value}
          {suffix && <span className="text-p-500 text-muted-foreground">{suffix}</span>}
        </div>
        {meterPct != null && (
          <div className="absolute left-0 right-0 bottom-0 h-[3px] bg-muted">
            <div
              className={cn('h-full', meterClass)}
              style={{ width: `${Math.max(0, Math.min(100, meterPct))}%` }}
            />
          </div>
        )}
      </CardContent>
    </Card>
  )
}

/** Pass-rate card tone matches the session-detail latency scale:
 * 100% good, ≥ 70% warn, below bad. */
function passRateTone(pct: number): StatTone {
  if (pct >= 100) return 'good'
  if (pct >= 70) return 'warn'
  return 'bad'
}

export const EvalRunDetailPage = ({
  runId,
  onBack,
  onCaseClick,
}: {
  runId: string
  onBack?: () => void
  onCaseClick?: (caseId: string) => void
}) => {
  const { run, loading, error } = useEvalRun(runId)
  const [openCaseId, setOpenCaseId] = useQueryState('case', parseAsString)
  const [localOpenCaseId, setLocalOpenCaseId] = useState<string | null>(null)
  const drawerCaseId = openCaseId ?? localOpenCaseId

  const handleRowClick = (caseId: string) => {
    if (onCaseClick) onCaseClick(caseId)
    else if (openCaseId !== undefined) void setOpenCaseId(caseId)
    else setLocalOpenCaseId(caseId)
  }
  const closeDrawer = () => {
    if (openCaseId !== null) void setOpenCaseId(null)
    setLocalOpenCaseId(null)
  }

  const stats = useMemo(() => {
    if (!run) return null
    const passRate = run.total > 0 ? Math.round((run.passed / run.total) * 100) : 0
    return {
      passRate,
      hasAnyFailure: run.failed > 0 || run.errored > 0,
      passedPct: run.total > 0 ? (run.passed / run.total) * 100 : 0,
      failedPct: run.total > 0 ? (run.failed / run.total) * 100 : 0,
    }
  }, [run])

  const columns = useMemo<ColumnDef<EvalCaseRow>[]>(
    () => [
      {
        id: 'name',
        accessorKey: 'name',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Name" />,
        cell: ({ row }) => (
          <span className="font-mono text-s-400">{row.original.name}</span>
        ),
        enableColumnFilter: true,
        meta: { label: 'Name', placeholder: 'Search name', variant: 'text' },
      },
      {
        id: 'file',
        accessorKey: 'file',
        header: ({ column }) => <DataTableColumnHeader column={column} label="File" />,
        cell: ({ row }) => (
          <span className="font-mono text-xs-400 text-muted-foreground">
            {row.original.file ?? '—'}
          </span>
        ),
        meta: { label: 'File' },
      },
      {
        id: 'status',
        accessorKey: 'status',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Status" />,
        cell: ({ row }) => <StatusChip status={row.original.status} />,
        enableColumnFilter: true,
        meta: {
          label: 'Status',
          variant: 'multiSelect',
          options: STATUS_OPTIONS,
        },
        filterFn: (row, id, value) => {
          if (!Array.isArray(value) || value.length === 0) return true
          return value.includes(row.getValue(id))
        },
      },
      {
        id: 'duration_ms',
        accessorKey: 'duration_ms',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Duration" />,
        cell: ({ row }) => (
          <span
            className={cn(
              'font-mono text-s-400 tabular-nums',
              durationToneClass(row.original.duration_ms),
            )}
          >
            {formatDuration(row.original.duration_ms)}
          </span>
        ),
        meta: { label: 'Duration' },
      },
      {
        id: 'judgments',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Judgments" />,
        cell: ({ row }) => {
          const c = row.original
          const judgePass = c.judgments.filter((j) => j.verdict === 'pass').length
          const judgeFail = c.judgments.filter((j) => j.verdict === 'fail').length
          if (c.judgments.length === 0) return <span className="text-muted-foreground">—</span>
          return (
            <span className="inline-flex items-center gap-2 text-s-400">
              {judgePass > 0 && (
                <span className="text-[hsl(var(--success-fg,var(--success)))] text-xs-600">
                  ✓ {judgePass} pass
                </span>
              )}
              {judgePass > 0 && judgeFail > 0 && (
                <span className="text-muted-foreground">·</span>
              )}
              {judgeFail > 0 && (
                <Badge
                  variant="outline"
                  className="text-xxs-600 text-[hsl(var(--destructive))] border-[hsl(var(--destructive-border))] bg-[hsl(var(--destructive-bg))] uppercase tracking-wider"
                >
                  {judgeFail} fail
                </Badge>
              )}
            </span>
          )
        },
      },
      {
        id: 'events',
        header: ({ column }) => <DataTableColumnHeader column={column} label="Events" />,
        cell: ({ row }) => (
          <span className="text-s-400 tabular-nums text-muted-foreground">
            {row.original.events.length}
          </span>
        ),
      },
    ],
    [],
  )

  const { table } = useDataTable({
    data: run?.cases ?? [],
    columns,
    pageCount: 1,
    initialState: { pagination: { pageIndex: 0, pageSize: 20 } },
    getRowId: (row) => row.case_id,
  })

  if (loading) {
    return (
      <div className="flex flex-col gap-5 p-6" aria-busy="true">
        <Skeleton className="h-8 w-64" />
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3">
          {Array.from({ length: 5 }).map((_, i) => (
            <Skeleton key={i} className="h-[110px] rounded-xl" />
          ))}
        </div>
        <Skeleton className="h-[300px] w-full rounded-xl" />
      </div>
    )
  }

  if (error || !run || !stats) {
    return (
      <div className="p-12 text-center text-foreground">
        <p>Failed to load eval run: {error ?? 'not found'}</p>
        {onBack && (
          <Button variant="ghost" size="sm" onClick={onBack} className="mt-4">
            <ArrowLeft className="h-3.5 w-3.5 mr-1" /> Back
          </Button>
        )}
      </div>
    )
  }

  return (
    <div className="p-6 flex flex-col gap-5 relative">
      {onBack && (
        <button
          type="button"
          onClick={onBack}
          className="inline-flex items-center gap-1.5 text-s-500 text-muted-foreground hover:text-foreground transition-colors bg-transparent border-none p-0 w-fit cursor-pointer"
        >
          <ArrowLeft className="h-3.5 w-3.5" /> Back to evals
        </button>
      )}

      <div className="flex items-start justify-between gap-4 flex-wrap">
        <div className="flex flex-col gap-1.5">
          <div className="flex items-center gap-3">
            <h1 className="text-h2-600 font-semibold m-0">
              {run.agent_id ?? <span className="text-muted-foreground">—</span>}
            </h1>
            <span className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-muted border text-xs-500">
              <FlaskConical className="h-3 w-3 text-muted-foreground" />
              {run.framework}
              {run.framework_version && (
                <span className="text-muted-foreground font-mono text-[11px]">
                  {run.framework_version}
                </span>
              )}
            </span>
          </div>
          <div className="font-mono text-xs-400 text-muted-foreground">{run.run_id}</div>
        </div>
        <div className="text-right text-s-400 text-muted-foreground">
          <b className="block text-foreground text-s-600">
            Started {formatDate(run.started_at)}
          </b>
          <span>Duration {formatDuration(run.duration_ms)}</span>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3">
        <StatCard
          label="Pass rate"
          value={stats.passRate}
          suffix="%"
          tone={passRateTone(stats.passRate)}
          meterPct={stats.passRate}
        />
        <StatCard
          label="Passed"
          value={run.passed}
          tone={run.passed > 0 ? 'good' : 'zero'}
          meterPct={stats.passedPct}
        />
        <StatCard
          label="Failed"
          value={run.failed}
          tone={run.failed > 0 ? 'bad' : 'zero'}
          meterPct={stats.failedPct}
        />
        <StatCard
          label="Errored"
          value={run.errored}
          tone={run.errored > 0 ? 'bad' : 'zero'}
        />
        <StatCard
          label="Skipped"
          value={run.skipped}
          tone={run.skipped > 0 ? 'warn' : 'zero'}
        />
      </div>

      {run.ci && (
        <Card>
          <CardContent className="flex flex-wrap items-center gap-4 py-3">
            <span className="text-xs-600 text-muted-foreground uppercase tracking-wider">CI</span>
            {run.ci.provider && (
              <span className="text-s-400 capitalize">{String(run.ci.provider)}</span>
            )}
            {run.ci.git_branch && (
              <span className="inline-flex items-center gap-1 text-s-400">
                <GitBranch className="h-3.5 w-3.5 text-muted-foreground" />
                {String(run.ci.git_branch)}
              </span>
            )}
            {run.ci.git_sha && (
              <span className="inline-flex items-center gap-1 text-s-400 font-mono">
                <GitCommit className="h-3.5 w-3.5 text-muted-foreground" />
                {String(run.ci.git_sha).slice(0, 7)}
              </span>
            )}
            {run.ci.run_url && (
              <a
                href={String(run.ci.run_url)}
                target="_blank"
                rel="noreferrer"
                className="inline-flex items-center gap-1 text-s-400 text-primary hover:underline"
              >
                View run <ExternalLink className="h-3 w-3" />
              </a>
            )}
            {run.ci.commit_message && (
              <span className="text-s-400 text-muted-foreground italic truncate max-w-[40ch]">
                "{String(run.ci.commit_message)}"
              </span>
            )}
          </CardContent>
        </Card>
      )}

      <div>
        <h2 className="text-h4-600 font-semibold mb-3">
          Cases{' '}
          <span className="text-muted-foreground text-s-400">
            ({table.getFilteredRowModel().rows.length} of {run.cases.length})
          </span>
        </h2>
        <ObsDataTable
          table={table}
          toolbar={<DataTableToolbar table={table} />}
          onRowClick={(row) => handleRowClick(row.original.case_id)}
        />
      </div>

      {!onCaseClick && (
        <Sheet
          open={!!drawerCaseId}
          onOpenChange={(open) => {
            if (!open) closeDrawer()
          }}
        >
          <SheetContent
            className="w-full sm:max-w-2xl md:max-w-3xl overflow-y-auto p-0"
            showCloseButton={false}
          >
            <SheetHeader className="sr-only">
              <SheetTitle>Case detail</SheetTitle>
            </SheetHeader>
            {drawerCaseId && (
              <EvalCaseDetailPage
                runId={runId}
                caseId={drawerCaseId}
                onBack={closeDrawer}
              />
            )}
          </SheetContent>
        </Sheet>
      )}
    </div>
  )
}
